shader:
// STEP 1: Tesla Coil Arc Breakdown
// STEP 2: Neon Topographic Schematic

float coilSDF(vec3 p) {
    // Primary Coil Base
    vec3 bp = p;
    float base = length(bp.xz) - 0.4;
    base = max(base, bp.y - 0.2); 

    // Top Toroid
    vec3 tp = p;
    tp.y -= 2.5;
    float r2 = length(tp.xz) - 1.8;
    float torus = sqrt(r2 * r2 + tp.y * tp.y) - 0.35;

    // Secondary Coil Column
    vec3 sp = p;
    sp.y -= 1.3;
    float col = length(sp.xz) - 0.35;
    col = max(col, -sp.y);

    return min(min(base, col), torus);
}

float arcField(vec3 p, float time) {
    vec3 start = vec3(0.0, 0.8, 0.0);
    vec3 end = vec3(0.0, 3.0, 0.0);

    float distAlong = length(p - start);
    float totalDist = length(end - start);

    if (distAlong > totalDist * 1.2) return 100.0;

    float progress = clamp(distAlong / totalDist, 0.0, 1.0);

    // Jitter and branching
    float jitter = sin(progress * 40.0 + time * 5.0) * 0.05 + 
                   cos(progress * 20.0 - time * 2.0) * 0.02;

    float width = 0.04 + abs(jitter) * 0.03;

    float branch1 = abs(p.z - (jitter + 0.02 * sin(progress * 50.0 + time * 10.0)));
    float branch2 = abs(p.z - (jitter - 0.02 * cos(progress * 55.0 + time * 12.0)));

    float d1 = abs(progress - (time + p.y * 0.1)) * 0.5;
    float d2 = branch1 + abs(p.y - (start.y + progress * totalDist)) * 0.5;
    float d3 = branch2 + abs(p.y - (start.y + progress * totalDist)) * 0.5;

    float field = min(d1, min(d2, d3));
    field = smoothstep(0.0, 0.02, width - field);

    float coronaTop = 1.0 / (0.1 + length(p - end));
    float coronaBot = 1.0 / (0.1 + length(p - start));

    return smoothstep(0.0, 0.1, field * 1.5 + coronaTop * 0.5 + coronaBot * 0.5);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float aspect = iResolution.x / iResolution.y;
    uv.x *= aspect;

    vec3 p = vec3(uv, 0.0);
    p.y -= 1.0;

    float structDist = coilSDF(p);
    bool hitCoil = structDist < 0.001;

    float arc = arcField(p, iTime);

    vec3 color = vec3(0.0);

    float contours = floor(arc * 8.0);

    if (arc > 0.01) {
        float band = fract(contours);
        color += vec3(1.0, 0.0, 0.8) * step(0.5, band);
        color += vec3(0.9, 0.2, 0.9) * smoothstep(0.2, 0.0, abs(arc - 0.15));
    }

    if (hitCoil) {
        color = vec3(1.0);
    } else if (structDist < 0.002) {
        color = vec3(0.8, 0.9, 1.0) * 0.6;
    }

    float grid = 0.0;
    grid += step(0.99, fract(p.x * 2.0));
    grid += step(0.99, fract(p.y * 2.0));
    color += vec3(0.1, 0.1, 0.1) * grid * 0.1;

    float vign = 1.0 - length(uv) * 0.6;
    color *= vign;

    color = pow(color, vec3(0.9));

    fragColor = vec4(color, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = (uv - 0.5) * vec2(1.6, 1.0);
    float t = iTime * 2.0;

    // 1. Geometric Structure: Ceramic Insulator Ribs
    // We use a polar grid with a radial offset to simulate the stepped ribs of a high-voltage insulator
    float r = length(p);
    float a = atan(p.y, p.x);

    // Create the "skeleton" of the insulator: a vertical column of repeating discs
    float discPos = (r + 0.5) * 12.0;
    float rib = sin(discPos + t * 0.2); 
    float diskProfile = smoothstep(0.4, 0.45, abs(fract(discPos) - 0.5));

    // Base ceramic color (dark, almost black with subtle blue tint)
    vec3 ceramic = vec3(0.02, 0.03, 0.08);

    // 2. The Phenomenon: Dielectric Breakdown
    // We generate a "fault line" using a high-frequency noise function modulated by the rib geometry
    float noiseVal = sin(p.x * 50.0 + t * 3.0) * sin(p.y * 30.0 - t * 2.0);
    float stress = abs(noiseVal);

    // The breakdown propagates along the ribs
    float arcThreshold = 0.85;
    float arcIntensity = smoothstep(arcThreshold - 0.2, arcThreshold, stress);

    // 3. Visual Style: Phosphoroscope / X-Ray Glow
    // The electric arcs are not just lines; they have a core and a halo
    vec3 coreColor = vec3(1.0, 0.9, 0.95); // White-hot
    vec3 plasmaColor = vec3(0.0, 0.8, 1.0) + vec3(0.3, 0.0, 0.5); // Cyan-Violet

    float glow = diskProfile * (0.3 + arcIntensity * 2.0);

    // Add a "flashover" wave that travels down the structure
    float wave = sin(r * 40.0 - t * 15.0 + noiseVal * 5.0);
    float flash = smoothstep(0.8, 0.99, wave * diskProfile);

    // Combine elements
    vec3 finalColor = ceramic + diskProfile * vec3(0.1); // Shading on ribs

    // Add the electric discharge
    float discharge = (arcIntensity + flash) * glow;
    vec3 arc = mix(coreColor, plasmaColor, fract(discharge));

    // Composite
    vec3 result = ceramic * (1.0 - smoothstep(0.0, 1.0, discharge)) + arc * discharge;

    // Vignette to focus on the center column
    float vign = 1.0 - smoothstep(0.4, 1.5, length(p));
    result *= vign;

    // CRT-like bloom simulation (simple additive overlay)
    result += result * 0.3; 

    fragColor = vec4(result, 1.0);
}

float random(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// Fractal Brownian Motion for surface noise
float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));

    // 3 octaves for porcelain texture
    for(int i = 0; i < 3; i++) {
        v += a * (random(p) - 0.5);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    // Slightly squash the aspect to focus on vertical insulator ribs
    uv.x *= 0.8; 

    float time = iTime;

    // Coordinate system centered on the insulator body
    vec2 q = uv * 3.0;
    float dist = length(q);

    // 1. The Porcelain Body (Ribs and Glaze)
    // Create the classic "ribbed" shape of a high-voltage insulator
    float ribs = abs(sin(uv.y * 15.0 + time * 0.5) * 0.5 + 0.5);
    float shape = 1.0 - smoothstep(1.8, 2.2, dist) * smoothstep(0.0, 0.4, abs(uv.y));

    // Add microscopic imperfections (glaze texture)
    float surfaceNoise = fbm(q * 8.0);
    float ceramic = mix(0.65, 0.9, smoothstep(0.0, 0.5, shape)) + surfaceNoise * 0.05;
    ceramic *= 1.0 + (ribs - 0.5) * 0.1; // Depth effect on ribs

    // 2. The Flashover (The Active Electricity)
    // We simulate a "dry band" arc forming from top to bottom
    float arcY = (time * 2.0 - 1.0) * 2.0; // Moves down
    float arcTime = sin(time * 3.14159); // Intensity pulse

    // Create a jagged, branching path based on noise
    float pathX = sin(uv.y * 10.0 + time) * 0.2 + random(vec2(uv.y, 10.0)) * 0.1;
    float distToArc = distance(uv.x, pathX);

    // The "Dry Band" effect: a thin, conductive channel that heats up
    float dryBand = 1.0 - smoothstep(0.002, 0.02, distToArc);

    // The actual ionized plasma
    // It only exists where the dry band is and the arc wavefront is passing
    float plasma = 0.0;
    float arcTrigger = smoothstep(-0.1, 0.1, arcY - uv.y);

    // Add a chaotic "forking" effect
    float chaos = random(vec2(uv.y, time * 10.0)) * 0.05;
    plasma += smoothstep(0.0, 0.03, arcTrigger) * dryBand * arcTime * (1.0 + chaos);

    // Secondary arcs (back-streaming)
    float secondary = smoothstep(0.0, 0.05, distance(uv, vec2(pathX + random(vec2(uv.y*50.0, time)) * 0.04, uv.y)));
    secondary *= smoothstep(-0.2, 0.2, arcY - uv.y + 0.1);
    plasma += secondary * 0.6;

    // 3. Color and Lighting
    vec3 porcelainColor = vec3(0.4, 0.6, 1.0); // Cobalt Blue/Grey

    // Ionized Gas Colors: Magenta/Cyan core to Yellow/White core
    vec3 plasmaColor = mix(
        vec3(0.8, 0.2, 1.0), // Outer violet/magenta
        vec3(1.0, 0.9, 0.4), // Inner yellow/white
        clamp(dryBand * 1.5, 0.0, 1.0)
    );

    // Combine
    vec3 col = porcelainColor * ceramic * 0.9;

    // Add glow and burn marks (carbonized trails)
    float carbonMark = max(0.0, arcTrigger - 0.3) * dryBand * 0.5;
    col = mix(col, vec3(0.1, 0.1, 0.15), carbonMark); // Darken to charred grey

    // Add the bright arc
    col += plasmaColor * plasma * 3.0;

    // Bloom/Glow simulation
    float glow = max(0.0, plasma * 2.0) * smoothstep(0.2, 0.0, distToArc);
    col += vec3(1.0, 0.9, 0.5) * glow;

    // Vignette for scientific focus
    col *= 1.0 - smoothstep(0.0, 2.0, length(uv));

    // Tone mapping and contrast
    col = col * col; // Squaring for contrast
    col = pow(col, vec3(0.9)); // Slight gamma

    fragColor = vec4(col, 1.0);
}

// No #version or precision needed; harness handles it.

float hash12(vec2 p) {
    p = fract(p * .1031);
    p += dot(p, p + 19.19);
    return fract(p.x * p.y);
}

float noise12(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = hash12(i);
    float b = hash12(i + vec2(1.0, 0.0));
    float c = hash12(i + vec2(0.0, 1.0));
    float d = hash12(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for(int i = 0; i < 5; i++) {
        v += a * noise12(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    // Animate time for the loop (2.0s)
    float t = iTime * 3.0; 

    // Base "thermal" background gradient
    vec2 q = vec2(0.);
    float dist = length(uv);

    // Create the "Streamer" channel path using fractal noise
    // We offset the noise field by time to create the jittering electron avalanche effect
    float n = fbm(uv * 15.0 + vec2(t * 2.0, t * 0.5));

    // Create the jagged path structure
    float channel = 0.0;
    // Define the main path as a narrow ridge in the noise field
    float threshold = 0.35 + 0.05 * sin(t * 5.0 + uv.x * 10.0);

    if (n > threshold) {
        // Ionized core (White Hot)
        channel = 1.0;
    } else {
        // Pre-ionization halo (Fading heat)
        float diff = n - threshold;
        if (diff > -0.15) {
            channel = smoothstep(-0.15, 0.0, diff) * 0.4;
        }
    }

    // Add "streamer" branches using distance fields and noise perturbation
    float branch = 0.0;
    vec2 p = uv * 20.0;
    float f = fbm(p);
    float line = sin(p.x * 10.0 + t * 2.0);
    float stepLine = step(0.98 - 0.02 * sin(t * 4.0), line);

    // Jitter the branch positions
    float jitter = hash12(vec2(floor(p.x * 2.0), t * 5.0));
    float branchDist = length(uv - vec2((p.x - jitter) / 20.0, 0.0));

    if (abs(line - 1.0) < 0.02) {
        branch = 1.0 - smoothstep(0.0, 0.005, branchDist) * (1.0 + sin(t * 15.0));
    }

    // Combine streamer and branches
    float intensity = max(channel, branch);

    // Add "breakdown" pulses (bright flashes)
    float pulse = sin(t * 3.0 + dist * 10.0);
    float flash = smoothstep(0.8, 1.0, pulse) * 0.3 * (1.0 - length(uv * 2.0));

    // Thermal palette: Dark Blue -> Cyan -> White -> Magenta (for extreme heat)
    vec3 col = vec3(0.05, 0.1, 0.2) * (1.0 - intensity); // Cold background
    col += vec3(0.3, 0.6, 1.0) * intensity;             // Ionized blue
    col += vec3(1.0, 1.0, 1.0) * pow(intensity, 2.0) * 0.8; // White core
    col += vec3(1.0, 0.1, 0.5) * pow(intensity, 3.0) * 0.4; // Overheated magenta

    // Apply the breakdown flash
    col += vec3(1.0) * flash;

    // Vignette for scientific plate look
    float v = 1.0 - length(uv * 1.5);
    col *= smoothstep(0.2, 1.0, v);

    // Scanline artifact (VHS/Oscilloscope)
    float scan = sin(uv.y * 400.0 + t * 50.0) * 0.02;
    col += vec3(scan);

    fragColor = vec4(col, 1.0);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}
float fbm(vec2 p) {
    float f = 0.0;
    float w = 0.5;
    for (int i = 0; i < 5; i++) {
        f += w * noise(p);
        p *= 2.0;
        w *= 0.5;
    }
    return f;
}
float arcFluctuation() {
    return sin(iTime * 8.0) * 0.1 + sin(iTime * 13.3) * 0.05 + hash(vec2(iTime)) * 0.02;
}
void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv *= 3.0;

    float time = iTime;
    float jitter = arcFluctuation();
    vec2 corePos = vec2(sin(time * 2.0 + jitter) * 0.05, cos(time * 2.3 + jitter) * 0.05);

    vec2 rel = uv - corePos;
    float dist = length(rel);

    // Molten pool geometry with organic distortion
    float n = fbm(rel * 4.0 + time * 0.5);
    float poolRadius = 0.45 - n * 0.08;

    // Distance field for the molten zone
    float dPool = dist - poolRadius;
    float softPool = smoothstep(-0.05, 0.05, dPool);

    // Core plasma intensity (inverse distance)
    float core = 1.0 - smoothstep(0.0, 0.08, dist);
    core = pow(core, 3.0); // Super bright center

    // Heat spread gradient
    float heat = smoothstep(1.2, 0.2, dist);
    heat *= (1.0 - softPool);

    // Color ramp: Black -> Blue -> Purple -> Red/Yellow -> White
    vec3 cCold = vec3(0.02, 0.02, 0.05);
    vec3 cBlue = vec3(0.1, 0.3, 0.8);
    vec3 cPurple = vec3(0.6, 0.1, 0.9);
    vec3 cYellow = vec3(1.0, 0.9, 0.3);
    vec3 cWhite = vec3(1.0, 1.0, 1.0);

    vec3 col = cCold;

    if (dist < poolRadius) {
        // Inside pool: Core dominates
        vec3 plasma = cWhite * core;
        vec3 molten = mix(cYellow, cPurple, smoothstep(0.1, 0.4, dist));
        col = mix(molten, plasma, core);

        // Add arc noise (ionization grain)
        float arcNoise = noise(rel * 100.0 + time * 15.0);
        col += vec3(0.1) * arcNoise * core;
    } else {
        // Outside pool: Heat affected zone
        float hGrad = smoothstep(0.5, 1.2, dist);
        col = mix(cPurple, cBlue, hGrad);
        col = mix(cBlue, cCold, hGrad);

        // Stress lines on cold metal
        if (hGrad > 0.5) {
            col *= 1.0 - fbm(uv * 30.0) * 0.1;
        }
    }

    // Vignette for industrial feel
    float vig = 1.0 - smoothstep(1.0, 2.5, length(uv));
    col *= vig;

    // Contrast boost
    col = pow(col, vec3(0.9));

    fragColor = vec4(col, 1.0);
}

// No version or precision needed (WebGL2 harness)
// Subject: Glaze Dielectric Flash in a Stoneware Kiln
// Style: Infrared Thermograph x Cyanotype

#define PI 3.14159265359

float noise(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
        v += a * noise(p);
        p *= 2.02;
        a *= 0.5;
    }
    return v;
}

float voronoi(vec2 p) {
    vec2 n = floor(p);
    vec2 f = fract(p);
    float m = 1e10;
    for (int j = -1; j <= 1; j++) {
        for (int i = -1; i <= 1; i++) {
            vec2 g = vec2(float(i), float(j));
            vec2 o = vec2(sin(g.x * 6.2831 + g.y * 1.57), cos(g.x * 4.712 + g.y * 3.1415));
            vec2 r = g + o * 0.4;
            float d = dot(r - f, r - f);
            if (d < m) m = d;
        }
    }
    return m;
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / min(iResolution.x, iResolution.y);

    // Kiln interior distortion (heat haze)
    vec2 q = uv * 1.5 + iTime * 0.05;
    q.x += 0.05 * sin(q.y * 3.0 + iTime);
    q.y += 0.05 * cos(q.x * 3.0 - iTime);

    // The Ceramic Body (Dark Blue/Cyanotype base)
    float ceramic = fbm(uv * 3.0 + iTime * 0.1);
    ceramic = 1.0 - smoothstep(0.0, 0.8, ceramic); // Inverted for dark clay

    // The Electrical Discharge (Dielectric Treeing)
    // We create a branching pattern that grows over time
    float t = fract(iTime * 0.5); // 2.0s loop

    vec2 center = vec2(0.0, 0.2); // Arc origin near top
    vec2 diff = uv - center;
    float dist = length(diff);

    // Fractal branching logic based on distance and noise
    float branch = 0.0;
    for (int i = 0; i < 6; i++) {
        float scale = 2.0;
        vec2 rot = vec2(sin(dist * 10.0 + float(i) * 1.0), cos(dist * 10.0 + float(i) * 1.0));
        vec2 p = (diff + rot * 0.1) * scale;
        float d = length(p) * 0.5 - t;
        branch += 0.1 * smoothstep(-0.05, 0.05, d) * (1.0 - abs(sin(p.x * 50.0)));
    }

    // Glaze Flash (Ionization)
    float glazeFlash = branch * 2.0;
    if (glazeFlash > 0.0) {
        glazeFlash = 1.0 - smoothstep(0.0, 1.0, glazeFlash);
    } else {
        glazeFlash = 0.0;
    }

    // Color Palette: Cyanotype (Deep Blue) -> Thermal (White/Red) -> Ion (Green/Purple)
    vec3 clayColor = vec3(0.05, 0.1, 0.25) + ceramic * vec3(0.02, 0.08, 0.15);
    vec3 arcColor = vec3(1.0, 0.95, 0.8);
    vec3 ionColor = vec3(0.0, 0.9, 0.5) * smoothstep(0.0, 0.5, branch) + 
                    vec3(0.9, 0.1, 0.9) * (1.0 - smoothstep(0.0, 0.5, branch));

    // Composite
    vec3 finalColor = clayColor;
    finalColor += arcColor * glazeFlash;
    finalColor += ionColor * branch * 0.6;

    // Vignette for kiln interior feel
    float vignette = 1.0 - length(uv);
    finalColor *= smoothstep(0.0, 1.0, vignette);

    // High contrast tone mapping for "burned" look
    finalColor = pow(finalColor, vec3(1.5));

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Aspect correction and scaling
    uv.x *= 1.33;

    // Time cycle: Charge (slow) then Discharge (fast)
    float t = iTime;
    float cycle = mod(t, 2.0);
    float phase = smoothstep(0.0, 1.5, cycle); // Charge phase

    // Discharge snap: a rapid, jittery spike
    float spark = 0.0;
    if (cycle > 1.5) {
        float snap = (cycle - 1.5) * 2.0; // 0.0 to 1.0
        // Fractal noise for the jagged arc path
        float n1 = sin(20.0 * snap + uv.x * 30.0) * cos(20.0 * snap + uv.y * 30.0);
        float n2 = sin(50.0 * snap + uv.x * 80.0) * cos(50.0 * snap + uv.y * 80.0);
        spark = abs(n1 + n2 * 0.5);
        // Intensity falls off rapidly after the peak
        spark *= (1.0 - snap); 
        spark = max(0.0, spark);
    }

    // Define the two electrodes (spheres)
    float d1 = length(uv - vec2(-0.6, 0.0));
    float d2 = length(uv - vec2(0.6, 0.0));
    float electrode = 1.0 - max(d1, d2); // Inverted distance for visual

    // Electric Field Gradient (Topographic lines)
    // Potential difference between spheres
    float V = abs(1.0 / max(d1, 0.01) - 1.0 / max(d2, 0.01));

    // Create hard iso-lines (Contour map style)
    float iso = fract(V * 15.0 + phase * 2.0);
    float lines = 1.0 - smoothstep(0.0, 0.05, iso) * smoothstep(1.0, 0.95, iso);

    // Combine: Base field + Electrodes + Spark
    vec3 col = vec3(0.05, 0.02, 0.1); // Deep violet void

    // Color map: Violet -> Teal -> White
    float intensity = V * 0.5;

    // Add the spark if active
    float arc = 0.0;
    if (spark > 0.02) {
        arc = spark * 3.0;
        // Constrain arc to the gap between spheres
        float mid = length(uv - vec2(0.0, 0.0));
        arc *= 1.0 - mid; // Fade out away from center gap
        if (arc > 0.5) arc = 0.0; // Hard cutoff for non-linear path
    }

    // Base field coloring (Thermal/Clinical look)
    vec3 fieldCol = mix(vec3(0.1, 0.0, 0.2), vec3(0.0, 0.4, 0.6), smoothstep(0.0, 1.0, intensity));

    // Apply contour lines as dark ink on the field
    col = mix(fieldCol, col, lines);

    // Superimpose the arc (High intensity white)
    col += vec3(1.0, 0.98, 0.9) * arc * 2.0;

    // Add electrode glow
    float glow = (1.0 - d1) * (1.0 - d2) * 0.5;
    col += vec3(0.8, 0.8, 1.0) * glow * 0.5;

    // Vignette and film grain simulation
    float vign = 1.0 - length(uv) * 0.8;
    col *= vign;

    fragColor = vec4(col, 1.0);
}

// Pseudo-random hash
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// 2D Noise for field distortion
float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

// Fractal Brownian Motion for jagged electricity
float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    for (int i = 0; i < 5; i++) {
        v += a * noise(p);
        p = p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv.x *= iResolution.x / iResolution.y;

    // Time loop: 0.0 to 1.0 over 2.0 seconds
    float t = mod(iTime, 2.0);
    float surge = smoothstep(0.0, 0.8, sin(t * 3.14159)) * smoothstep(1.0, 0.0, t);

    // Define the arc path (parabolic curve from top to bottom)
    vec2 rodTop = vec2(0.0, 1.5);
    vec2 rodBot = vec2(0.2, -1.5);
    vec2 center = (rodTop + rodBot) * 0.5;

    // Distance to the arc line
    vec2 p = uv - center;
    // Rotate to align arc
    float angle = atan(rodBot.y - rodTop.y, rodBot.x - rodTop.x);
    vec2 rp = vec2(cos(angle), sin(angle));
    vec2 perp = vec2(-sin(angle), cos(angle));

    float d = dot(uv - center, perp);
    float distAlongArc = dot(uv - rodTop, rp);

    // Create the jagged channel
    float channel = fbm(vec2(distAlongArc * 4.0 + t * 2.0, d * 10.0));
    float arcWidth = 0.15 + surge * 0.3;

    // The main lightning channel
    float lightning = max(0.0, arcWidth - abs(d - channel * 0.2));
    lightning = pow(smoothstep(0.0, arcWidth * 1.5, lightning), 3.0);

    // Ionization halo
    float halo = 1.0 / (1.0 + 40.0 * length(uv - center) - surge * 20.0);
    halo = smoothstep(0.0, 1.0, halo) * 0.6 * surge;

    // Voltage field lines (radial distortion)
    float field = fbm(uv * 10.0 + vec2(t * 0.5, 0.0));
    float fieldOverlay = smoothstep(0.4, 0.8, field) * surge * 0.3;

    // Color composition
    vec3 base = vec3(0.05, 0.05, 0.1); // Wet asphalt dark purple
    vec3 core = vec3(1.0, 1.0, 0.95);  // Blinding white center
    vec3 mid = vec3(0.2, 0.4, 1.0);    // Electric blue
    vec3 outer = vec3(0.8, 0.2, 1.0);  // Violet plasma

    vec3 color = base;
    color += mid * halo;
    color += outer * fieldOverlay;

    // Mix the lightning channel
    color += mix(mid, core, smoothstep(0.0, 0.1, lightning)) * lightning * 3.0 * surge;

    // Vignette for "wet asphalt" depth
    float vig = smoothstep(1.5, 0.0, length(uv));
    color = mix(color, vec3(0.0), 1.0 - vig);

    // Scanline/Grit texture
    float scan = (fract(gl_FragCoord.y * 0.05) < 0.02) ? 0.2 : 0.0;
    color *= 1.0 + scan * 0.2;

    // Final gamma correction
    color = pow(color, vec3(1.0 / 2.2));

    fragColor = vec4(color, 1.0);
}

float hash(vec2 p) { return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453); }
float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    return mix(mix(hash(i), hash(i + vec2(1, 0)), f.x),
               mix(hash(i + vec2(0, 1)), hash(i + vec2(1, 1)), f.x), f.y);
}
vec2 voronoi(vec2 p) {
    vec2 n = floor(p);
    vec2 f = fract(p);
    vec2 m = vec2(1000.0);
    vec2 c;
    for (int j = -1; j <= 1; j++) {
        for (int i = -1; i <= 1; i++) {
            vec2 g = vec2(float(i), float(j));
            vec2 o = vec2(hash(n + g), hash(n + g + vec2(13.0, 13.0)));
            vec2 r = g + o - f;
            float d = dot(r, r);
            if (d < m.x) { m = r; c = n + g + o; }
        }
    }
    return c;
}

float arc(vec2 p, float t) {
    float d = 0.0;
    float amp = 1.2;
    float freq = 0.05;
    float iter = 6.0;

    p *= 1.5;
    vec2 start = vec2(0.0, -0.5);
    vec2 end = vec2(0.5, 0.5);

    // Base distance
    vec2 diff = p - start;
    float dist = length(diff);

    // Add branching chaos
    for (float i = 0.0; i < iter; i++) {
        vec2 pos = p - (start + (end - start) * (dist / (amp * 1.5)));
        float n = noise(vec2(i * 10.0 + t * 5.0, pos.x * 3.0 + t * 2.0));
        float branch = n * (0.05 + (1.0 - dist) * 0.1);
        pos += vec2(branch, 0.0) * (i * 0.2);
        float d2 = distance(p, pos);
        d = min(d, d2 * 0.95);
    }

    // Snap to Voronoi edges for fracture look
    vec2 cell = voronoi(p * 4.0);
    float cellDist = distance(p * 4.0, cell) / 4.0;
    d = min(d, cellDist * 1.5);

    // Pulse the arc
    float pulse = smoothstep(0.0, 2.0, t) * smoothstep(2.0, 0.0, t - 0.5);
    pulse += sin(t * 10.0) * 0.2;

    return d * (1.0 + pulse * 0.5);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 p = uv;

    // Background: Soot-stained ceramic with faint grid
    float grid = 0.05 / (sin(uv.x * 60.0) * sin(uv.y * 60.0) + 2.0);
    float ceramic = 0.05 + noise(uv * 5.0) * 0.02;
    ceramic *= 0.8 + 0.2 * sin(uv.y * 10.0 - iTime * 0.5);

    vec3 bg = vec3(0.02, 0.01, 0.01) + vec3(ceramic, ceramic * 0.9, ceramic * 0.8) * 0.1;
    bg += vec3(grid * 0.05);

    // The Arc
    float arcVal = arc(uv, iTime);
    float glow = 1.0 / (arcVal * arcVal + 0.001);
    glow = pow(glow, 0.7);

    // Color palette: Red plasma to deep crimson
    vec3 core = vec3(1.0, 1.0, 0.9);
    vec3 mid = vec3(1.0, 0.2, 0.05);
    vec3 outer = vec3(0.6, 0.0, 0.0);

    vec3 arcColor = mix(outer, mid, smoothstep(0.5, 0.0, arcVal));
    arcColor = mix(arcColor, core, smoothstep(0.2, 0.0, arcVal));

    // Combine
    vec3 finalCol = bg + arcColor * glow * 0.4;

    // Add sparks
    float spark = 0.0;
    for(int i=0; i<5; i++) {
        vec2 s = vec2(hash(vec2(float(i), iTime)), hash(vec2(float(i)+1.0, iTime)));
        vec2 pos = vec2(0.0, -0.5) + (vec2(0.5, 0.5) - vec2(0.0, -0.5)) * s.x + (s.y - 0.5) * 0.5;
        float d = distance(uv, pos);
        spark += 1.0 / (d * d + 0.01) * 0.1;
    }
    finalCol += vec3(1.0, 0.8, 0.4) * spark;

    // Vignette for old plate look
    float vig = 1.0 - length(uv) * 0.6;
    finalCol *= vig;

    // Tone mapping / film grain
    finalCol = pow(finalCol, vec3(0.9));
    float grain = hash(uv + iTime) * 0.05;
    finalCol += vec3(grain);

    fragColor = vec4(finalCol, 1.0);
}

// Arc Welder's Glow in Red Safety Glass
// WebGL2 Fragment Shader

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 4; i++) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 q = uv * 2.0;

    // Time looped for 2 seconds
    float t = mod(iTime, 2.0);
    float arcPulse = sin(t * 3.14159 * 4.0); 
    arcPulse = smoothstep(0.2, 0.8, arcPulse);

    // Center of the arc
    vec2 center = vec2(0.0);
    // Jitter the arc slightly
    vec2 jitter = vec2(hash(vec2(t, 1.0)), hash(vec2(t, 2.0))) * 0.02;
    center += jitter;

    // Molten pool structure
    float d = length(uv - center);

    // Fractal detail for the molten metal surface
    float f = fbm(uv * 10.0 + vec2(t, t * 0.5));

    // Corona effect (inverse distance + noise)
    float corona = 1.0 / (d * 2.0 + 0.1);
    corona *= (1.0 + 0.2 * noise(uv * 3.0 - t));

    // The Arc Core: extremely bright, shrinking with pulse
    float core = 1.0 - smoothstep(0.0, 0.02 + f * 0.01, d);
    core = pow(core, 3.0) * arcPulse;

    // Color Palette: PURE RED THEME
    // Base: Deep Black (void of the safety glass)
    vec3 col = vec3(0.0);

    // Glow Layer 1: Deep Red (background heat)
    col += vec3(0.8, 0.0, 0.0) * corona * 0.4;

    // Glow Layer 2: Crimson/Orange (molten metal)
    float metalHeat = mix(0.0, 1.0, clamp(corona, 0.0, 1.0));
    vec3 molten = vec3(1.0, 0.3, 0.1);
    col += molten * metalHeat * 0.8;

    // Glow Layer 3: White-Hot Red (The Arc)
    vec3 arcColor = vec3(1.0, 0.6, 0.6);
    col += arcColor * core * 2.5;

    // Add grain (safety glass texture)
    float grain = hash(gl_FragCoord.xy + vec2(t * 10.0));
    col *= 1.0 + (grain - 0.5) * 0.05;

    // Vignette to simulate the goggle lens
    float vign = 1.0 - length(uv);
    col *= smoothstep(0.2, 1.5, vign);

    // Final Tone Mapping to keep it punchy
    col = col * (1.0 + col); 
    col = sqrt(col);

    fragColor = vec4(col, 1.0);
}

vec2 hash2(vec2 p) {
    p = fract(p * vec2(23.7, 21.3));
    p += dot(p, p + 20.7);
    return -1.0 + 2.0 * fract(p * p);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(mix(hash2(i).x, hash2(i + vec2(1.0, 0.0)).x, f.x),
               mix(hash2(i + vec2(0.0, 1.0)).x, hash2(i + vec2(1.0, 1.0)).x, f.x), f.y);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float time = iTime;

    // Subject: Fractured grid lines representing overloaded infrastructure
    float grid = abs(mod(uv.x * 20.0, 2.0) - 1.0) + abs(mod(uv.y * 20.0, 2.0) - 1.0);
    float dist = min(abs(uv.x), abs(uv.y));
    float structure = smoothstep(0.05, 0.0, grid) + 0.2 * smoothstep(0.02, 0.0, dist);

    // Phenomenon: Arcing electricity using fractal noise and sine waves
    float arc = 0.0;
    vec2 arcUv = uv * 3.0;
    float phase = sin(time * 3.14) * 2.0; // 2s loop

    for (int i = 0; i < 5; i++) {
        arcUv += vec2(sin(arcUv.y * 2.0 + time * float(i) * 0.5) * 0.05, 
                      cos(arcUv.x * 2.0 + time * float(i) * 0.5) * 0.05);
        arc += noise(arcUv * float(i + 1) + phase) * 0.5;
    }

    // Combine structure and arc
    float intensity = structure + arc * (1.5 - phase * 0.5);

    // Lens: Red cyanotype with thermal bloom and crack artifacts
    vec3 col = vec3(0.0);

    // Base: Dark industrial void
    col += vec3(0.05, 0.02, 0.02) * intensity;

    // Arc Color: Intense red to white heat
    float heat = smoothstep(0.5, 2.0, intensity);
    col += vec3(1.0, 0.1, 0.1) * heat * 2.0; // Core white-red
    col += vec3(1.0, 0.0, 0.0) * (1.0 - heat) * intensity * 3.0; // Outer crimson

    // Crack artifact simulation (stained glass / thermal stress)
    float crack = smoothstep(0.95, 1.0, noise(uv * 50.0 + time * 0.1));
    col *= mix(1.0, 0.2, crack * 0.5);

    // Bloom effect via simple radial glow
    vec2 center = vec2(0.0);
    float glow = 0.5 / (length(uv - center * 1.5) + 0.1);
    col *= (1.0 + 0.2 * glow * intensity);

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 p = uv * 6.0;

    // Time factors
    float t = iTime;
    float cycle = mod(t, 2.0);

    // Base: Silicon Wafer (Dark Grey/Blue)
    vec3 col = vec3(0.05, 0.1, 0.25); // Cyanotype background

    // Grid: Conductive Busbars (White/Cyan)
    float grid = abs(sin(p.x * 8.0)) * abs(sin(p.y * 8.0));
    float bars = step(0.98, abs(sin(p.x * 8.0))) + step(0.98, abs(sin(p.y * 8.0)));

    // Solar Pulse (Green Electricity Trigger)
    float wave = sin(p.y * 4.0 - t * 6.0) + sin(p.x * 4.0 - t * 6.0);
    float energy = smoothstep(0.2, 1.0, wave);

    // Electron Flow (Dots moving along grid)
    float dotFlow = step(0.95, fract((p.x + p.y) * 12.0 + t * 5.0));
    dotFlow *= bars; // Only on wires

    // Terminal Points (High contrast)
    float term = smoothstep(0.4, 0.42, abs(p.y) + abs(p.x));

    // Color Mixing
    vec3 base = col;

    // Grid lines (Silver/White)
    base += vec3(0.8, 0.9, 1.0) * bars * 0.3;

    // Solar Hit (Bright Green Flash)
    base += vec3(0.2, 1.0, 0.6) * energy * 0.8;

    // Electrons (Bright Yellow/White)
    base += vec3(1.0, 0.9, 0.5) * dotFlow * 2.0;

    // Overprint effect (Rough edges simulation)
    float noise = sin(p.x * 100.0) * sin(p.y * 100.0);
    if (noise > 0.99) base *= 0.0; // Grain

    // Annotated Schematic Look
    if (uv.y > 0.3 && abs(uv.x) < 0.2) {
        float text = step(0.0, fract(p.x * 20.0 - t) + sin(p.y * 20.0));
        base = mix(base, vec3(0.0, 0.8, 0.0), text * 0.3);
    }

    // Gamma curve for print look
    col = base;
    col = pow(col, vec3(1.8));

    // Hard clip for Riso style
    float intensity = dot(col, vec3(0.33, 0.33, 0.33));
    col = step(0.05, intensity) * col * 1.2;

    // Additive bloom for high energy areas
    if (energy > 0.8 || dotFlow > 0.9) {
        col += vec3(0.1);
    }

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = iTime * 1.5; // Loop speed adjusted for ~2s cycle

    // Blade geometry: twisted airfoil profile
    float x = uv.x * 2.0;
    float y = uv.y * 2.0;

    // Base airfoil shape (NACA-ish approximation)
    float thickness = 0.8 * (1.0 - pow(abs(x), 3.0));
    float camber = 0.15 * (x - x * x * x);
    float bladeBody = length(vec2(x, y - camber)) - thickness * 0.3;

    // Twisted rotation based on height (simulating 3D twist)
    float twist = x * 0.5; 
    vec2 twistedUV = vec2(
        uv.x * cos(twist) - uv.y * sin(twist),
        uv.x * sin(twist) + uv.y * cos(twist)
    );

    // Vibration function: simulate aerodynamic load flex
    // High frequency at tip, low at root
    float load = sin(t + x * 20.0) * 0.1 * (0.5 + x) + 0.5;
    float flex = sin(t * 2.0) * (0.1 * x * x); 

    // Distance field for the stressed blade
    float d = distance(vec2(twistedUV.x, twistedUV.y + flex), vec2(0.0, 0.0)) - thickness * 0.3;

    // Contour generation: Stress lines based on gradient of load
    float stressGradient = abs(sin(t + x * 15.0)) * (1.0 + x);

    // Topographic bands
    float bandWidth = 0.05;
    float bands = fract(d / bandWidth + stressGradient);

    // Thermal stress overlay (white lines where stress is high)
    float stressLines = 1.0 - smoothstep(0.8, 1.0, stressGradient);

    // Mask to blade shape
    float mask = smoothstep(-0.02, 0.02, d);

    // Cyanotype Palette: Deep Indigo background, White highlights
    vec3 baseColor = vec3(0.02, 0.08, 0.25); // Deep Prussian Blue
    vec3 highlight = vec3(0.9, 0.95, 1.0);   // Cyanotype White

    // Combine bands and stress
    float finalVal = mix(mask, 1.0 - bands, 0.8) * stressLines;

    vec3 col = mix(baseColor, highlight, finalVal);

    // Add grid noise for "schematic" feel
    float grid = sin(uv.x * 100.0) * sin(uv.y * 100.0) * 0.05;

    fragColor = vec4(col + grid, 1.0);
}

float hash(vec2 p) { return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453); }
float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = mix(mix(hash(i + vec2(0,0)), hash(i + vec2(1,0)), f.x),
                  mix(hash(i + vec2(0,1)), hash(i + vec2(1,1)), f.x), f.y);
    return n * 0.5 + 0.5;
}

float grid(vec2 p, float width, float spacing) {
    float x = mod(p.x, spacing) / spacing * 2.0 - 1.0;
    float y = mod(p.y, spacing) / spacing * 2.0 - 1.0;
    return max(1.0 - abs(x) / width, 1.0 - abs(y) / width);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    vec2 p = uv;
    vec3 col = vec3(0.02, 0.1, 0.15); // Deep silicon teal base

    // Photovoltaic Cell Grid
    float cellSize = 0.4;
    vec2 cellCoord = floor(p / cellSize) * cellSize;
    vec2 local = p - cellCoord;
    float cellPattern = sin(local.x * 20.0 + iTime) * cos(local.y * 20.0 + iTime);
    cellPattern = smoothstep(-0.5, 0.5, cellPattern);

    // Add texture noise to cells
    float texNoise = noise(p * 5.0 + iTime * 0.2);
    col += vec3(0.05, 0.15, 0.05) * (cellPattern * texNoise + 0.2);

    // Main Busbars (Gold)
    float spacing = 1.2;
    float lineWidth = 0.08;
    float flowSpeed = 2.0;

    // Calculate flow offset based on time to loop at 2.0s
    float timeMod = mod(iTime, 2.0) / 2.0;
    float offset = sin(iTime * 3.14159 * 2.0) * 0.5 + 0.5; // Pulse amplitude

    float gridX = grid(p + vec2(-timeMod, 0.0), lineWidth, spacing);
    float gridY = grid(p + vec2(0.0, -timeMod), lineWidth, spacing);
    float gridTotal = max(gridX, gridY);

    // Gold busbar color with flow pulsation
    vec3 gold = vec3(1.0, 0.8, 0.3) * (0.6 + 0.4 * offset);
    gold += vec3(0.2, 0.4, 0.6) * smoothstep(0.8, 1.0, gridTotal) * (0.5 + 0.5 * sin(iTime * 10.0));

    col += gold * gridTotal;

    // Current surge effect (cyan wave traveling along lines)
    float surge = sin((p.x + p.y) * 2.0 - iTime * 5.0 + hash(p * 10.0));
    float surgeMask = smoothstep(0.9, 1.0, gridTotal) * smoothstep(-0.5, 1.0, surge);
    col += vec3(0.2, 0.9, 1.0) * surgeMask * 0.8;

    // Annotate schematic corners
    float corner = length(p) - 1.2;
    if (corner < -0.5) {
        col += vec3(0.8) * smoothstep(-0.5, 0.0, corner);
    }

    // Vignette
    float vig = 1.0 - length(uv) * 0.4;
    col *= vig;

    fragColor = vec4(col, 1.0);
}

vec2 hash2(vec2 p) {
    p = fract(p * 0.3183099 + vec2(0.1031, 0.1030));
    p += dot(p, p + 0.1030);
    return -1.0 + 2.0 * fract(p);
}

float gridDist(vec2 p, float size, float gap) {
    float x = abs(fract(p.x / size) - 0.5) * size;
    float y = abs(fract(p.y / size) - 0.5) * size;
    return max(0.0, max(x, y) - gap / 2.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 p = uv * 1.2;

    // Grid structure
    float cellSize = 0.15;
    float lineW = 0.008;
    float dist = gridDist(p, cellSize, lineW * 2.0);

    // Time-based pulse flow
    float t = iTime;
    float phase = sin(t * 3.14 * 2.0 + p.y * 2.0);
    float pulse = smoothstep(0.5, 1.0, sin(t * 3.14) + 0.5);

    // Inverter nodes at intersections
    vec2 ip = floor(p / cellSize) * cellSize;
    float nodeDist = length(p - ip);
    float nodeSize = 0.02 + pulse * 0.03;

    // Combine grid lines and nodes
    float gridColor = 1.0 - smoothstep(lineW, lineW * 2.5, dist);
    float nodeColor = 1.0 - smoothstep(nodeSize, nodeSize * 1.5, nodeDist);

    // Energy flow effect
    float flow = smoothstep(0.8, 1.0, pulse * (1.0 - dist * 5.0));
    float finalMask = max(gridColor, nodeColor) * (0.6 + 0.4 * flow);

    // Color palette: Deep teal to Electric Green to White
    vec3 bg = vec3(0.02, 0.05, 0.08);
    vec3 gridCol = vec3(0.0, 0.8, 0.4); // Matrix Green
    vec3 pulseCol = vec3(0.8, 1.0, 0.6); // Bright Green/White

    vec3 col = bg + gridCol * finalMask * 2.0 + pulseCol * flow * 0.8;

    // Vignette for focus
    float vig = 1.0 - length(uv * 0.8);
    col *= pow(vig, 0.5);

    fragColor = vec4(col, 1.0);
}

float hash(vec2 p) { return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453); }

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f*f*(3.0-2.0*f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float f = 0.0;
    float amp = 0.5;
    for (int i = 0; i < 5; i++) {
        f += amp * noise(p);
        p *= 2.0;
        amp *= 0.5;
    }
    return f;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 c = uv - 0.5;
    c.x *= iResolution.x / iResolution.y;

    float t = iTime * 2.0;
    float rot = sin(t * 1.5);

    // Blade geometry: twisted airfoil shape moving across screen
    float dist = distance(c, vec2(c.x * 0.2 + rot, 0.0));
    float bladeX = (c.x - rot) * 0.8;
    float wingProfile = 0.5 - abs(c.y * 2.0); 
    if (bladeX < 0.0) wingProfile = 0.0;

    float bladeShape = max(0.0, 1.0 - length(vec2(bladeX - 0.3, c.y * 1.5)) * 2.0);
    bladeShape *= smoothstep(0.0, 0.05, bladeX);

    // Stress field: high at root and tip, dynamic load
    vec2 localPos = vec2(bladeX * 2.0, c.y * 4.0);
    float load = sin(t * 3.0 + localPos.x * 5.0) * 0.5 + 0.5;
    float stress = smoothstep(0.0, 1.0, bladeShape) * (0.2 + 0.8 * load * (1.0 - abs(localPos.x - 1.0)));

    // Topographic contour effect
    float n = fbm(localPos * 4.0 + vec2(t, t * 0.5));
    float iso = sin(stress * 20.0 + n * 3.0) * 0.5 + 0.5;

    // Coloring: Engineering Heatmap style
    vec3 rootColor = vec3(0.1, 0.6, 0.8); // Cyan (Cool)
    vec3 tipColor = vec3(1.0, 0.1, 0.6);  // Magenta (Hot)

    vec3 base = mix(rootColor, tipColor, stress * 1.2);
    vec3 finalColor = mix(vec3(0.05), base, smoothstep(0.4, 0.6, iso));

    // Add grid lines for schematic feel
    float grid = 1.0 - smoothstep(0.9, 1.0, sin(c.x * 60.0) * sin(c.y * 60.0) * 0.5 + 0.5);
    finalColor = mix(finalColor, vec3(0.2), grid * 0.1);

    // Bloom/Glow on high stress
    float glow = smoothstep(0.8, 1.0, stress) * 0.5;
    finalColor += vec3(glow);

    fragColor = vec4(finalColor, 1.0);
}

vec2 hash(vec2 p) {
    return fract(sin(p) * 43758.5453);
}

float grid(float t, float x, float y) {
    vec2 g = abs(fract(vec2(x, y) * 4.0) - 0.5);
    return 1.0 - smoothstep(0.02, 0.04, g.x + g.y);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float time = mod(iTime, 2.0);

    // Schematic Grid Background
    vec2 coord = uv * 20.0;
    float bgGrid = grid(0.0, coord.x, coord.y);
    vec3 baseColor = vec3(0.05, 0.06, 0.08);
    vec3 lineColor = vec3(0.8, 0.85, 0.9);

    // Scanning Energy Beam
    float scanX = (time * 20.0) * 0.5;
    float scanWidth = 0.8;
    float scan = 1.0 - smoothstep(scanX - scanWidth, scanX, uv.x) * smoothstep(scanX, scanX + scanWidth, uv.x);

    // Cells
    vec2 cellUV = coord - floor(coord);
    // Convert bool logic to float 0.0 or 1.0 explicitly
    float cellMask = step(0.5, cellUV.x) * step(0.5, cellUV.y);

    // Active Green Electricity Effect
    // Ensure isCellActive is a float, not a bool
    float isCellActive = step(0.5, 1.0 - cellMask) * step(0.5, scan);

    // Hatching for inactive cells
    float hatch = step(1.0, mod(coord.x + coord.y, 2.0)) * 0.2;

    vec3 finalColor = baseColor;

    // Use float comparisons for if statements
    if (cellMask < 0.5) {
        if (isCellActive > 0.5) {
            // Glowing Green Core
            vec3 greenCore = vec3(0.0, 0.9, 0.3);
            vec3 greenGlow = vec3(0.0, 1.2, 0.6) * (0.5 + 0.5 * sin(time * 10.0));

            // Intensity based on scan position
            float intensity = smoothstep(0.0, 1.0, scan);

            finalColor = mix(vec3(0.1), greenCore, intensity);
            finalColor += greenGlow * intensity * (1.0 - length(cellUV - 0.5));
        } else {
            // Inactive cell with schematic hatching
            finalColor = mix(baseColor, vec3(0.2, 0.25, 0.3), 0.5);
            if (hatch > 0.1) {
                finalColor = mix(finalColor, lineColor, 0.4);
            }
        }
    } else {
        // Background grid
        finalColor = mix(baseColor, lineColor * bgGrid, 0.5);
    }

    // Add technical scanlines for CRT/Schematic feel
    float scanlines = sin(gl_FragCoord.y * 2.0 + time * 5.0) * 0.02;
    finalColor += scanlines;

    // Vignette
    float vignette = 1.0 - length(uv * 0.8);
    finalColor *= vignette;

    fragColor = vec4(finalColor, 1.0);
}

// Green Electricity: Photovoltaic Lattice Pulse
// No external textures, pure procedural hex grid with energy flow

// Simplex-like hash for pseudo-random offsets per cell
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

void main() {
    // Normalize coordinates centered
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Hex grid transformation
    vec2 h = uv * vec2(0.866, 1.0) * 10.0; // Scale and skew for hex
    h.y += h.x * 0.577;

    // Map to hex cell indices
    vec2 i = floor(h);
    vec2 f = fract(h) - 0.5;

    // Hex distance field
    float d = 0.0;
    if (f.x < 0.0) d = max(max(f.x - 1.0, f.y + 0.577), f.y);
    else if (f.x > 0.0) d = max(max(f.x, -f.y + 0.577), f.y);
    else d = max(f.x, -f.y + 0.577);

    // Distance to hex boundary
    float dist = abs(d) - 0.2; // 0.2 is the hex "thickness"

    // Create a wave of energy flowing diagonally
    float wave = sin(uv.x * 4.0 + uv.y * 4.0 + iTime * 3.0);

    // Per-cell phase offset based on hash to make it look like random activation
    float cellPhase = hash(i);

    // Combine wave and cell activation
    float activation = smoothstep(0.2, 1.0, wave) * (0.8 + 0.2 * sin(iTime * 5.0 + cellPhase * 6.0));

    // Base color: dark slate
    vec3 color = vec3(0.05, 0.08, 0.12);

    // Grid lines
    float gridLine = 1.0 - smoothstep(0.0, 0.02, dist);
    color += vec3(0.1, 0.15, 0.18) * gridLine;

    // Energy glow (Green electricity)
    // The energy surges through the center of the hex
    float energy = (1.0 - smoothstep(-0.1, 0.1, dist)) * activation;

    // Color palette: Deep Green to Neon Lime
    vec3 darkGreen = vec3(0.0, 0.3, 0.1);
    vec3 neonLime = vec3(0.2, 1.0, 0.3);
    vec3 whiteHot = vec3(1.0, 1.0, 0.9);

    // Interpolate based on energy intensity
    if (energy > 0.1) {
        float t = smoothstep(0.1, 0.8, energy);
        vec3 mid = mix(darkGreen, neonLime, t);
        color += mid * 2.0; // Boost brightness

        // Add "hot" center
        if (energy > 0.7) {
            color += whiteHot * (energy - 0.7) * 1.5;
        }
    }

    // Scanline effect for technical schematic feel
    float scan = sin(gl_FragCoord.y * 15.0 + iTime * 10.0);
    color *= 0.95 + 0.05 * scan;

    // Vignette
    float vig = 1.0 - length(uv) * 0.4;
    color *= vig;

    // Gamma correction
    color = pow(color, vec3(0.9));

    fragColor = vec4(color, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv.x *= 1.2;

    float t = iTime;

    // Base: Wet Asphalt / Dark Grid
    vec3 col = vec3(0.05);
    float grid = length(mod(uv + vec2(0.0, 0.0), 0.05) - 0.025);
    col += 0.02 / max(0.001, grid);

    // Silicon Layers (Cross-section)
    float y = uv.y;
    float layerBase = smoothstep(-0.15, -0.12, y);
    float layerTop = smoothstep(0.12, 0.15, y);
    float layerMid = smoothstep(-0.12, 0.12, y);

    // P-N Junction Glow
    float junction = layerMid * (1.0 - layerTop) * (1.0 - layerBase);
    float pulse = sin(t * 3.14) * 0.3 + 0.7;
    junction *= pulse;

    // Conductive Grid Lines (Fingers)
    float fingers = 0.0;
    for (int i = -5; i <= 5; i++) {
        float xDist = abs(uv.x - float(i) * 0.1);
        fingers += 0.1 / max(0.001, xDist * (1.0 + abs(uv.y)));
    }

    // Electron Flow Stream
    float flow = sin(uv.y * 20.0 + t * 5.0);
    float stream = smoothstep(0.4, 1.0, flow) * junction;

    // Color Composition
    // Anti-reflective layer (Top): Dark Purple/Blue
    vec3 cTop = vec3(0.1, 0.0, 0.2) * layerTop;
    // Depletion Zone: Cyan/Green Bioluminescence
    vec3 cMid = mix(vec3(0.0, 0.8, 1.0), vec3(0.0, 1.0, 0.4), stream) * junction;
    // Conductive Fingers: Silver/White
    vec3 cGrid = vec3(0.9) * smoothstep(0.0, 0.5, fingers);

    // Combine
    col += cTop;
    col += cMid;
    col += cGrid * 0.4;

    // Vignette & Contrast
    float vign = 1.0 - length(uv);
    col *= smoothstep(0.0, 1.0, vign);

    fragColor = vec4(col, 1.0);
}

float hash(float n) { return fract(sin(n) * 43758.5453123); }
float noise(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f*f*(3.0-2.0*f);
    float n = p.x + p.y*57.0;
    return mix(mix(hash(n+0.0), hash(n+1.0), f.x),
               mix(hash(n+57.0), hash(n+58.0), f.x), f.y);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 st = uv * 10.0;

    // Time factor for looping pulse
    float t = iTime * 2.5;
    float cycle = sin(t);
    float pulse = smoothstep(0.0, 1.0, cycle + 0.5);

    // Grid structure representing the silicon lattice
    float grid = 1.0 - smoothstep(0.01, 0.02, fract(st.x)) * 
                 smoothstep(0.01, 0.02, fract(st.y));
    vec3 base = vec3(0.05, 0.08, 0.12); // Dark glass bg

    // PN Junction line
    float junction = abs(uv.x - sin(uv.y * 4.0 + t) * 0.2);
    float junctionGlow = 1.0 / (junction * 8.0 + 0.1);

    // Electron flow particles
    float flow = noise(st * 2.0 + vec2(t, t * 0.5));
    flow = step(0.4, flow);
    float flowPos = sin(st.x * 20.0 + t * 4.0);
    float activeFlow = smoothstep(0.0, 0.8, flowPos) * flow * pulse;

    // Color mixing
    vec3 color = base;

    // Grid lines in faint blue
    color += vec3(0.2, 0.3, 0.4) * grid * 0.3;

    // Junction glow (Green/Teal)
    vec3 junctionCol = vec3(0.2, 0.9, 0.3) * junctionGlow;
    color += junctionCol * 0.8;

    // Active electrons (Bright Green)
    color += vec3(0.1, 1.2, 0.4) * activeFlow * 2.0;

    // Subtle vignette for focus
    float vig = 1.0 - length(uv) * 0.6;
    color *= vec3(vig);

    fragColor = vec4(color, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = (uv - 0.5) * 2.0;
    p.x *= iResolution.x / iResolution.y;

    // Time-based loop for 2s cycle
    float t = iTime;

    // Hexagonal lattice structure representing silicon crystal
    float s = 0.15;
    vec2 q = vec2(dot(p, vec2(0.866, 0.5)), dot(p, vec2(-0.5, 0.866))) / s;
    vec3 col = vec3(0.0); // Deep obsidian base

    float f = length(floor(q + vec2(0.5, 0.5))) * s;
    float d = min(length(p - f * vec2(0.866, 0.5)), length(p - f * vec2(-0.5, 0.866)));

    // Simulated solar flare impact (moving light source)
    vec2 sunPos = vec2(sin(t * 3.14) * 0.3, cos(t * 1.57) * 0.3);
    float dist = length(p - sunPos);
    float flare = exp(-dist * 4.0) * (1.0 - smoothstep(0.2, 0.4, dist));

    // Thermal glow intensity based on flare
    float heat = smoothstep(0.4, 0.0, d) * flare * 2.0;

    // Electron flow vectors (rising blue streams)
    float flow = sin(p.x * 20.0 - t * 5.0) * sin(p.y * 20.0 - t * 5.0);
    float stream = max(0.0, flow) * heat * 0.8;

    // Grid lines for schematic look
    float grid = step(0.95, fract(p.x * 10.0)) * 0.1 + step(0.95, fract(p.y * 10.0)) * 0.1;
    grid *= 0.3; // Subtle overlay

    // Color composition
    // Base: Dark Silicon
    col += vec3(0.05, 0.05, 0.08);

    // Heat: Magenta to White
    col += vec3(1.0, 0.2, 0.8) * heat;
    col += vec3(1.0, 1.0, 1.0) * heat * heat;

    // Flow: Electric Blue
    col += vec3(0.0, 0.6, 1.0) * stream;

    // Schematic Grid
    col += vec3(0.2, 0.2, 0.3) * grid;

    // Clamp and tone map
    col = clamp(col, 0.0, 1.2);
    fragColor = vec4(pow(col, vec3(0.9)), 1.0);
}
